// src/components/About.jsx
import { personal } from '../data/portfolio';

const cards = [
  { icon: '⚛', title: 'Frontend', text: 'React, Angular, JavaScript ES6, HTML5, CSS3. Interfaces dinámicas y componentes reutilizables.' },
  { icon: '⚙', title: 'Backend', text: '.NET (C#), PHP. Lógica de negocio y gestión de modelos de datos en entornos empresariales.' },
  { icon: '🗄', title: 'Databases', text: 'SQL Server, MySQL. Consultas, gestión y optimización de bases de datos relacionales.' },
  { icon: '📊', title: 'BI & Tools', text: 'Power BI, Qlik. Análisis y visualización de datos empresariales.' },
];

export default function About() {
  const { bio, contact } = personal;

  return (
    <section id="about" style={s.section}>
      <div style={s.inner}>
        <div className="reveal">
          <p style={s.label}>About me / Sobre mí</p>
          <h2 style={s.title}>Who I am</h2>
        </div>

        <div style={s.grid}>
          {/* Left: bio + info */}
          <div>
            {bio.map((p, i) => (
              <p key={i} className={`reveal reveal-delay-${i + 1}`} style={s.bioPara}>
                {p}
              </p>
            ))}

            <div className="reveal" style={s.infoList}>
              {[
                { label: 'Location', val: contact.location },
                { label: 'Email',    val: contact.email,    href: `mailto:${contact.email}` },
                { label: 'LinkedIn', val: 'rubén-marco',    href: contact.linkedin },
                { label: 'Portfolio',val: 'unsitiogenial.es', href: contact.portfolio },
                { label: 'Idiomas',  val: contact.languages },
                { label: 'Extras',   val: contact.extras },
              ].map((item) => (
                <div key={item.label} style={s.infoItem}>
                  <span style={s.infoLabel}>{item.label}</span>
                  {item.href ? (
                    <a href={item.href} target="_blank" rel="noreferrer" style={s.infoLink}>
                      {item.val}
                    </a>
                  ) : (
                    <span style={s.infoVal}>{item.val}</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Right: cards */}
          <div style={s.cards}>
            {cards.map((c, i) => (
              <div
                key={c.title}
                className={`reveal reveal-delay-${i + 1}`}
                style={s.card}
                onMouseEnter={e => (e.currentTarget.style.borderColor = 'rgba(232,58,58,0.25)')}
                onMouseLeave={e => (e.currentTarget.style.borderColor = 'var(--border)')}
              >
                <div style={s.cardIcon}>{c.icon}</div>
                <div>
                  <div style={s.cardTitle}>{c.title}</div>
                  <div style={s.cardText}>{c.text}</div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

const s = {
  section: { background: 'var(--bg2)', padding: '100px 5%' },
  inner:   { maxWidth: 1200, margin: '0 auto' },
  label:   { fontSize: 11, fontWeight: 600, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--accent)', marginBottom: 10 },
  title:   { fontFamily: 'var(--font-head)', fontSize: 'clamp(30px, 5vw, 50px)', fontWeight: 800, letterSpacing: '-2px', color: 'var(--text)', marginBottom: 56 },
  grid:    { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 64, alignItems: 'start' },
  bioPara: { fontSize: 15, color: 'var(--text2)', lineHeight: 1.82, marginBottom: 18, fontWeight: 300 },
  infoList:{ display: 'flex', flexDirection: 'column', gap: 10, marginTop: 32, paddingTop: 28, borderTop: '1px solid var(--border)' },
  infoItem:{ display: 'flex', gap: 14, alignItems: 'baseline' },
  infoLabel:{ fontSize: 11, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text3)', minWidth: 76 },
  infoVal: { fontSize: 14, color: 'var(--text)' },
  infoLink:{ fontSize: 14, color: 'var(--accent2)', textDecoration: 'none' },
  cards:   { display: 'flex', flexDirection: 'column', gap: 16 },
  card:    {
    background: 'var(--card)', border: '1px solid var(--border)',
    borderRadius: 12, padding: '20px 24px',
    display: 'flex', alignItems: 'flex-start', gap: 18,
    transition: 'border-color 0.2s',
  },
  cardIcon: {
    width: 42, height: 42, borderRadius: 10,
    background: 'rgba(232,58,58,0.09)',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    fontSize: 18, flexShrink: 0,
  },
  cardTitle:{ fontFamily: 'var(--font-head)', fontSize: 15, fontWeight: 700, color: 'var(--text)', marginBottom: 4 },
  cardText: { fontSize: 13, color: 'var(--text2)', lineHeight: 1.6 },
};
